#include <stdio.h>
#include <string.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[100], t[100];
        scanf("%s %s", s, t);
        int lenS = strlen(s), lenT = strlen(t);
        int lcmLen = lcm(lenS, lenT);
        char result[lcmLen + 1];
        for (int i = 0; i < lcmLen; i++) {
            result[i] = s[i % lenS];
        }
        result[lcmLen] = '\0';
        printf("%s\n", result);
    }
    return 0;
}

