int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        string s, t;
        cin >> s >> t;
        int lenS = s.length(), lenT = t.length();
        int lcmLen = lcm(lenS, lenT);
        string result;
        for (int i = 0; i < lcmLen; i++) {
            result += s[i % lenS];
        }
        cout << result << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;

public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static int lcm(int a, int b) {
        return (a * b) / gcd(a, b);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            String s = scanner.next(), tStr = scanner.next();
            int lenS = s.length(), lenT = tStr.length();
            int lcmLen = lcm(lenS, lenT);
            StringBuilder result = new StringBuilder();
            for (int i = 0; i < lcmLen; i++) {
                result.append(s.charAt(i % lenS));
            }
            System.out.println(result.toString());
        }
    }
}

